#include <bits/stdc++.h>

using namespace std;

long long mod=1e9+7;



long long power(long long a, long long n, long long mod){

  long long res=1;

    while(n>0){

     if(n&1)

         res=(res*a)%mod;

     a=(a*a)%mod;

     n>>=1;

  }

return res;

}



long long inverse(long long a, long long mod){

  return power(a,mod-2,mod);

}



int main(){

  long long n,k,arr[100005];

  long long a[100005], b[100005];

  cin>>n>>k;

  for(int i=0;i<n;i++)

       cin>>arr[i];

  a[0]=1;

  b[0]=1;

  for(int i=1;i<=n;i++){

    a[i]=(i*a[i-1])%mod;

    b[i]=inverse(a[i],mod);

  }

  sort(arr,arr+n);

  long long ans=0;

  for(int i=0;i<n-k+1;i++){

    long long x=1;

    x=(x*a[n-i-1])%mod;

    x=(x*b[k-1])%mod;

    x=(x*b[n-i-k])%mod;

    x=(arr[n-i-1]*x)%mod;

    ans=(ans+x+mod)%mod;

   }

  for(int i=0;i<n-k+1;i++){

    long long x=1;

    x=(x*a[n-1-i])%mod;

    x=(x*b[k-1])%mod;

    x=(x*b[n-i-k])%mod;

    x=(arr[i]*x)%mod;

    ans=(ans-x+mod)%mod;

  }

  cout<<ans<<endl;

}
